// packages/canvas/src/state/schema/objects.ts
export type CanvasGeometry = {
  x: number;
  y: number;
  width: number;
  height: number;
};

export type InteractiveCanvasObject = {
  id: string;
  type: InteractiveCanvasObjectType;
  /** The object's ONE text field (D3/D11) — replaces the legacy `label`/`body`/`title` trio.
      The kind decides rendering; may be empty. Connections keep their own separate `label`. */
  text: string;
  /** The object's ONE color pick (D1/D12/D17) — a swatch id from the closed 10-pick roster
      (state/schema/colors.ts). Absent = the kind's first-use default. */
  color?: CanvasColor;
  parentId?: string | null;
  geometry: CanvasGeometry;
  style?: CanvasObjectStyle;
  layout?: {
    mode: "free" | "row" | "column" | "stack";
    padding?: number;
    gap?: number;
  };
  /** `type: "section"` only (W2) — two-mode section lock. */
  locked?: "all" | "background";
  /** arrow-shape | chevron | parallelogram: "left" | "right" (default "right");
      triangle: "up" | "down" (default "up"). */
  direction?: CanvasShapeDirection;
  /** `type: "sticky"` only. */
  author?: string;
  /** `type: "icon"` only (W5) — REQUIRED glyph selector (26 ids in CanvasIconGlyph);
      missing/unknown is a hard validation error. */
  icon?: CanvasIconGlyph;
};

// packages/canvas/src/state/schema/connections.ts
export type CanvasConnectionStyle = "solid" | "dashed";

export type CanvasArrowDirection = "none" | "forward" | "back" | "both";

export type CanvasConnectionEndpoint = {
  objectId: string;
  anchor?: "top" | "right" | "bottom" | "left" | "center";
  /**
   * Relative anchor point on the endpoint object's bounds, as
   * [0..1, 0..1] fractions of (width, height) from the top-left corner.
   * Optional — when present, used by A* routing as a more precise anchor
   * than the coarse `anchor` side; when absent, routing falls back to
   * `anchor` / auto-picked sides.
   */
  position?: [number, number];
};

export type InteractiveCanvasConnection = {
  id: string;
  from: CanvasConnectionEndpoint;
  to: CanvasConnectionEndpoint;
  label?: string;
  style?: CanvasConnectionStyle;
  arrow?: CanvasArrowDirection;
  role?: string;
  /** Stroke color pick — a swatch id from the closed 10-id roster. */
  color?: CanvasColor;
  /** Optional world-space polyline override. */
  waypoints?: Array<[number, number]>;
};
